// === INPUT ===
let chart = $json;

// Se vier como string dentro de "output" (resposta do Agente), faz o parse
if (chart.output && typeof chart.output === 'string') {
  try {
    // 1. EXTRAÇÃO ROBUSTA: Pega tudo desde o primeiro '{' até o último '}'
    // Isso ignora textos como "Aqui está o JSON:" antes ou "Espero ter ajudado" depois.
    const jsonMatch = chart.output.match(/\{[\s\S]*\}/);

    // Se não encontrar chaves, tenta usar a string original (fallback)
    let jsonString = jsonMatch ? jsonMatch[0] : chart.output;

    // 2. LIMPEZA DE SUJEIRA INTERNA (Markdown e Comentários)
    const jsonClean = jsonString
      .replace(/```json/g, '')   // remove ```json
      .replace(/```/g, '')       // remove ```
      .replace(/\/\/.*$/gm, '')  // remove // comentários de linha
      .replace(/\/\*[\s\S]*?\*\//g, ''); // remove /* ... */ comentários de bloco

    chart = JSON.parse(jsonClean);

  } catch (e) {
    // Dica de Debug: Mostra o que ele tentou parsear para você corrigir no prompt se necessário
    throw new Error(`❌ Falha ao converter chart.output para JSON: ${e.message} ||| Conteúdo recebido: ${chart.output}`);
  }
}

// Fallback: Se chart não tiver estrutura válida, retorna erro ou ignora
if (!chart || (!chart.values && !chart.data)) {
    // Retorna algo vazio ou erro controlado se preferir
    return [{ json: { error: "Sem dados para gráfico", originalOutput: chart?.output } }];
}

// === BASE CONFIG ===
// ... (MANTENHA O RESTANTE DO CÓDIGO DAQUI PARA BAIXO IGUAL AO ANTERIOR) ...
const baseUrl = 'https://image-charts.com/chart.js/2.8.0';
const background = 'white';
const colors = [
  'rgba(78,121,167,1)',   // Azul
  'rgba(242,142,43,1)',   // Laranja
  'rgba(225,87,89,1)',    // Vermelho
  'rgba(118,183,178,1)',  // Verde-azulado
  'rgba(89,161,79,1)',    // Verde
  'rgba(237,201,73,1)',   // Amarelo
  'rgba(175,122,161,1)',  // Roxo
  'rgba(255,157,167,1)',  // Rosa
  'rgba(156,117,95,1)',   // Marrom
  'rgba(186,176,171,1)',  // Cinza
];

let datasets = [];
let config;

// Função Helper para montar datasets
// Suporta tanto Array simples [10, 20] quanto Objeto {"TI": [10], "RH": [20]}
// Função Helper para montar datasets
// Suporta tanto Array simples [10, 20] quanto Objeto {"Set/25": [10], "Out/25": [20]}
const buildDatasets = (values, type) => {
    const isMultiSeries = !Array.isArray(values) && typeof values === 'object';

    if (isMultiSeries) {
        return Object.entries(values).map(([label, data], i) => ({
            label: label, // Nome da série (ex: "Setembro/2025")
            data: data,
            fill: type === 'line' ? false : true,
            // Usa cores diferentes para cada mês/série
            borderColor: colors[i % colors.length],
            // Se for barra, usa cor sólida (1). Se linha, usa cor sólida também.
            backgroundColor: type === 'line' ? colors[i % colors.length] : colors[i % colors.length].replace('1)', '0.8)'), 
            borderWidth: 1, // Borda mais fina para barras agrupadas fica mais elegante
            tension: 0.3, 
            pointRadius: 4 // Ponto um pouco maior para linhas múltiplas
        }));
    } else {
        // Série Única (Ex: Ranking simples)
        return [{
            label: chart.descricao || 'Valores',
            data: values,
            fill: type === 'line' ? false : true,
            borderColor: colors[0],
            backgroundColor: type === 'line' ? colors[0] : colors[0].replace('1)', '0.7)'),
            borderWidth: 2,
            tension: 0.3,
            pointRadius: 3
        }];
    }
};

// === 1. GRÁFICO DE LINHA ===
if (chart.tipo === 'linha') {
  datasets = buildDatasets(chart.values, 'line');

  config = {
    type: 'line',
    data: {
      labels: chart.labels,
      datasets: datasets
    },
    options: {
      responsive: true,
      title: { display: true, text: chart.titulo },
      legend: { position: 'top', display: true },
      scales: {
        yAxes: [{ ticks: { beginAtZero: true } }] // Garante que o eixo Y comece do 0
      }
    }
  };
}

// === 2. GRÁFICO DE PIZZA (COM DADOS NA LEGENDA E DECIMAIS) ===
else if (chart.tipo === 'pizza') {
  // Garante que values seja um array simples
  const dataValues = Array.isArray(chart.values) ? chart.values : Object.values(chart.values)[0];

  // 1. Calcula o Total
  const total = dataValues.reduce((a, b) => a + b, 0);

  // 2. Cria "Labels Ricos" com 1 casa decimal (Ex: "Feminino: 317 (35,8%)")
  const richLabels = chart.labels.map((label, i) => {
      const value = dataValues[i];

      // MUDANÇA AQUI:
      // toFixed(1) garante 1 casa decimal.
      // replace('.', ',') troca ponto por vírgula para formato BR.
      const percent = total > 0 
        ? ((value / total) * 100).toFixed(1).replace('.', ',') 
        : '0,0';

      return `${label}: ${value} (${percent}%)`;
  });

  datasets = [{
    data: dataValues,
    backgroundColor: colors.slice(0, chart.labels.length),
    borderColor: 'white',
    borderWidth: 2
  }];

  config = {
    type: 'pie',
    data: {
      labels: richLabels, 
      datasets: datasets
    },
    options: {
      responsive: true,
      title: { display: true, text: chart.titulo },
      legend: { 
          position: 'right',
          labels: { 
            boxWidth: 12, 
            fontSize: 11,
            padding: 15
          } 
      },
      plugins: {
        datalabels: { 
            display: true, 
            color: 'white', 
            font: { weight: 'bold', size: 14 },
            anchor: 'center',
            align: 'center',
                    }
      }
    }
  };
}

// === 3. GRÁFICO HORIZONTAL (Correção v2.8.0) ===
else if (chart.tipo === 'horizontal') {
  datasets = buildDatasets(chart.values, 'bar');

  config = {
    type: 'horizontalBar', // <--- CORREÇÃO CRÍTICA PARA CHART.JS 2.X
    data: {
      labels: chart.labels,
      datasets: datasets
    },
    options: {
      responsive: true,
      title: { display: true, text: chart.titulo },
      legend: { position: 'right', display: datasets.length > 1 }, // Esconde legenda se for só 1 série
      scales: {
        xAxes: [{ ticks: { beginAtZero: true } }]
      }
    }
  };
}

// === 4. GRÁFICO DE BARRAS VERTICAIS (Padrão) ===
else {
  datasets = buildDatasets(chart.values, 'bar');

  config = {
    type: 'bar',
    data: {
      labels: chart.labels,
      datasets: datasets
    },
    options: {
      responsive: true,
      title: { display: true, text: chart.titulo },
      legend: { position: 'top', display: datasets.length > 1 },
      scales: {
        yAxes: [{ ticks: { beginAtZero: true } }]
      }
    }
  };
}

// === GERAR URL ===
// Adicionando encodeURIComponent para garantir que caracteres especiais não quebrem a URL
const jsonConfig = encodeURIComponent(JSON.stringify(config));
const url = `${baseUrl}?bkg=${background}&c=${jsonConfig}`;

return [{
  json: { url, chart }
}];
